using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using System.IO;
using System.Threading.Tasks;

[Route("api/[controller]")]
[ApiController]
public class UploadController : ControllerBase
{
    private readonly string[] _permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" };
    private readonly long _fileSizeLimit = 10 * 1024 * 1024; // 10 MB
    private readonly string _targetFilePath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");

    [HttpPost("upload")]
    public async Task<IActionResult> UploadFile(IFormFile file)
    {
        if (file == null)
        {
            return BadRequest("No file uploaded.");
        }
        
        var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (string.IsNullOrEmpty(fileExtension) || !_permittedExtensions.Contains(fileExtension))
        {
            return BadRequest("Invalid file type.");
        }

        if (file.Length > _fileSizeLimit)
        {
            return BadRequest("File size exceeds limit.");
        }

        var filePath = Path.Combine(_targetFilePath, $"{Guid.NewGuid()}{fileExtension}");

        if (!Directory.Exists(_targetFilePath))
        {
            Directory.CreateDirectory(_targetFilePath);
        }

        using (var fileStream = new FileStream(filePath, FileMode.Create))
        {
            await file.CopyToAsync(fileStream);
        }

        return Ok(new { FilePath = $"/uploads/{Path.GetFileName(filePath)}" });
    }
}